import api from './index';
import type { PaginatedResponse } from '@/types/api';
import type { MediaResource } from '@/types/media';

export interface WatchHistoryItem {
  id: number;
  userId: number;
  mediaResourceId: number;
  currentTime: number;
  duration?: number;
  watchDuration: number;
  isCompleted: boolean;
  episodeNumber?: number;
  playCount: number;
  lastPlayedAt?: string | Date;
  createdAt: string | Date;
  updatedAt: string | Date;
  mediaResource: MediaResource;
}

export interface WatchHistoryStats {
  totalWatched: number;
  completed: number;
  watching: number;
  totalWatchTime: number;
}

export const watchHistoryApi = {
  // 获取当前用户观看历史
  getMyWatchHistory: (params?: any) => {
    return api.get<PaginatedResponse<WatchHistoryItem>>(
      '/watch-history/user/me',
      { params },
      false,
    );
  },

  // 获取用户的观看历史
  getUserWatchHistory: (_userId?: string | number, params?: any) => {
    return api.get<PaginatedResponse<WatchHistoryItem>>(
      '/watch-history/user/me',
      { params },
      false,
    );
  },

  // 获取用户统计信息
  getUserStats: (_userId?: string | number) => {
    return api.get<WatchHistoryStats>('/watch-history/user/me/stats', undefined, false);
  },

  // 获取用户继续观看列表
  getContinueWatching: (_userId?: string | number, params?: any) => {
    return api.get<WatchHistoryItem[]>('/watch-history/user/me/continue', { params }, false);
  },

  // 获取用户已看完列表
  getCompleted: (_userId?: string | number, params?: any) => {
    return api.get<PaginatedResponse<WatchHistoryItem>>(
      '/watch-history/user/me/completed',
      { params },
      false,
    );
  },

  // 记录观看进度
  recordProgress: (data: {
    mediaResourceId: string | number;
    currentTime: number;
    duration?: number;
    episodeNumber?: number;
    isCompleted?: boolean;
  }) => {
    return api.post<WatchHistoryItem>('/watch-history', data);
  },

  // 更新观看进度
  updateProgress: (
    mediaResourceId: string | number,
    data: { currentTime: number; duration?: number },
  ) => {
    return api.patch<WatchHistoryItem>('/watch-history/progress', undefined, {
      params: {
        mediaResourceId,
        currentTime: data.currentTime,
        duration: data.duration,
      },
    });
  },

  // 删除观看历史
  deleteWatchHistory: (id: string) => {
    return api.delete<void>(`/watch-history/${id}`);
  },
};

import { ref, reactive, onUnmounted, onMounted } from 'vue';
import io from 'socket.io-client';
type Socket = any;
import { useAuthStore } from '@/stores/auth';
import type {
  DanmakuMessage,
  RoomInfo,
  HeartbeatResponse,
  DanmakuSettings,
  DanmakuServiceConfig,
} from '@/types/danmaku';

const DEV = import.meta.env.DEV;

export type { DanmakuMessage, RoomInfo, HeartbeatResponse, DanmakuSettings, DanmakuServiceConfig };

// WebSocket服务类
export class DanmakuWebSocketService {
  private socket: Socket | null = null;
  private reconnectAttempts = 0;
  private maxReconnectAttempts = 5;
  private reconnectInterval: number;
  private heartbeatInterval: number | null = null;
  private isConnected = ref(false);
  private roomId = ref('');
  private userId = ref('');

  // 事件监听器
  private listeners = new Map<string, Set<Function>>();

  // 消息队列（在重连时暂存）
  private messageQueue: any[] = [];

  // 配置选项
  private options = {
    reconnectDelay: 1000,
    heartbeatInterval: 30000,
    maxQueueSize: 100,
    autoReconnect: true,
  };

  constructor(private authStore: any) {}

  // 连接WebSocket
  connect(videoId: string, userId: string) {
    try {
      this.roomId.value = videoId;
      this.userId.value = userId;

      const config: DanmakuServiceConfig = {
        serverUrl: (import.meta.env.VITE_WS_URL || 'ws://localhost:3334') + '/danmaku',
        reconnectDelay: this.options.reconnectDelay,
        heartbeatInterval: this.options.heartbeatInterval,
        maxQueueSize: this.options.maxQueueSize,
        autoReconnect: this.options.autoReconnect,
        maxReconnectAttempts: this.maxReconnectAttempts,
      };

      this.socket = io(config.serverUrl, {
        auth: {
          token: this.authStore.token,
          videoId,
          userId,
        },
        transports: ['websocket', 'polling'],
        timeout: 10000,
        reconnection: true,
        reconnectionAttempts: config.maxReconnectAttempts,
        reconnectionDelay: config.reconnectDelay,
      });

      this.setupEventHandlers();
    } catch (error) {
      console.error('❌ WebSocket连接失败:', error);
      this.handleConnectionError(error);
    }
  }

  // 设置事件处理器
  private setupEventHandlers() {
    if (!this.socket) return;

    // 连接成功
    this.socket.on('connect', () => {
      if (DEV) {
        console.log('[DanmakuWS] connected');
      }
      this.isConnected.value = true;
      this.reconnectAttempts = 0;

      // 加入房间
      this.socket?.emit('join-room', {
        videoId: this.roomId.value,
        userId: this.userId.value,
      });

      // 发送队列中的消息
      this.flushMessageQueue();

      // 开始心跳
      this.startHeartbeat();

      // 触发连接成功事件
      this.emit('connected');
    });

    // 连接断开
    this.socket.on('disconnect', reason => {
      if (DEV) {
        console.log('[DanmakuWS] disconnected:', reason);
      }
      this.isConnected.value = false;
      this.stopHeartbeat();
      this.emit('disconnected', reason);

      // 自动重连
      if (this.options.autoReconnect && reason !== 'io client disconnect') {
        this.handleReconnect();
      }
    });

    // 连接错误
    this.socket.on('connect_error', error => {
      console.error('❌ WebSocket连接错误:', error);
      this.handleConnectionError(error);
    });

    // 接收弹幕消息
    this.socket.on('danmaku-message', (message: DanmakuMessage) => {
      this.emit('message', message);
    });

    // 接收房间信息
    this.socket.on('room-info', (info: RoomInfo) => {
      this.emit('room-info', info);
    });

    // 心跳响应
    this.socket.on('heartbeat-response', (response: HeartbeatResponse) => {
      this.emit('heartbeat', response);
    });

    // 错误消息
    this.socket.on('error', error => {
      console.error('❌ WebSocket错误:', error);
      this.emit('error', error);
    });
  }

  // 发送弹幕消息
  sendDanmaku(message: Omit<DanmakuMessage, 'id' | 'timestamp'>) {
    if (!this.isConnected.value || !this.socket) {
      // 添加到消息队列
      this.addToMessageQueue({
        event: 'send-danmaku',
        data: message,
      });
      return;
    }

    this.socket.emit('send-danmaku', {
      ...message,
      videoId: this.roomId.value,
      userId: this.userId.value,
      timestamp: Date.now(),
      id: this.generateMessageId(),
    });
  }

  // 获取房间信息
  getRoomInfo() {
    if (!this.isConnected.value || !this.socket) return;

    this.socket.emit('get-room-info', {
      videoId: this.roomId.value,
    });
  }

  // 心跳检测
  private startHeartbeat() {
    this.stopHeartbeat();

    this.heartbeatInterval = window.setInterval(() => {
      if (this.isConnected.value && this.socket) {
        this.socket.emit('heartbeat', {
          userId: this.userId.value,
          timestamp: Date.now(),
        });
      }
    }, this.options.heartbeatInterval);
  }

  private stopHeartbeat() {
    if (this.heartbeatInterval) {
      clearInterval(this.heartbeatInterval);
      this.heartbeatInterval = null;
    }
  }

  // 重连处理
  private handleReconnect() {
    if (this.reconnectAttempts >= this.maxReconnectAttempts) {
      if (DEV) {
        console.warn('[DanmakuWS] reached max reconnect attempts');
      }
      this.emit('reconnect-failed');
      return;
    }

    this.reconnectAttempts++;
    if (DEV) {
      console.log(
        `[DanmakuWS] reconnecting (${this.reconnectAttempts}/${this.maxReconnectAttempts})`,
      );
    }

    this.reconnectInterval = window.setTimeout(() => {
      if (this.roomId.value && this.userId.value) {
        this.connect(this.roomId.value, this.userId.value);
      }
    }, this.options.reconnectDelay * this.reconnectAttempts);
  }

  // 连接错误处理
  private handleConnectionError(error: any) {
    this.isConnected.value = false;
    this.emit('error', error);

    // 如果启用了自动重连，尝试重连
    if (this.options.autoReconnect) {
      this.handleReconnect();
    }
  }

  // 消息队列管理
  private addToMessageQueue(message: any) {
    if (this.messageQueue.length >= this.options.maxQueueSize) {
      // 队列满，移除最旧的消息
      this.messageQueue.shift();
    }
    this.messageQueue.push(message);
  }

  private flushMessageQueue() {
    if (!this.isConnected.value || !this.socket) return;

    const messages = [...this.messageQueue];
    this.messageQueue = [];

    messages.forEach(message => {
      switch (message.event) {
        case 'send-danmaku':
          this.sendDanmaku(message.data);
          break;
        // 其他消息类型处理
      }
    });
  }

  // 事件管理
  on(event: string, callback: Function) {
    if (!this.listeners.has(event)) {
      this.listeners.set(event, new Set());
    }
    this.listeners.get(event)!.add(callback);
  }

  off(event: string, callback: Function) {
    const callbacks = this.listeners.get(event);
    if (callbacks) {
      callbacks.delete(callback);
    }
  }

  private emit(event: string, ...args: any[]) {
    const callbacks = this.listeners.get(event);
    if (callbacks) {
      callbacks.forEach(callback => {
        try {
          callback(...args);
        } catch (error) {
          console.error('❌ 事件回调执行错误:', error);
        }
      });
    }
  }

  // 工具方法
  private generateMessageId(): string {
    return `${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
  }

  // 状态获取
  get connected(): boolean {
    return this.isConnected.value;
  }

  get currentRoomId(): string {
    return this.roomId.value;
  }

  get currentUserId(): string {
    return this.userId.value;
  }

  // 断开连接
  disconnect() {
    if (this.socket) {
      this.socket.disconnect();
      this.socket = null;
    }

    this.stopHeartbeat();
    this.isConnected.value = false;
    this.reconnectAttempts = 0;
    this.messageQueue = [];

    // 清理事件监听器
    this.listeners.clear();

    // 清理重连定时器
    if (this.reconnectInterval) {
      clearTimeout(this.reconnectInterval);
      this.reconnectInterval = 0;
    }
  }

  // 销毁服务
  destroy() {
    this.disconnect();
  }
}

// 创建全局服务实例
let danmakuService: DanmakuWebSocketService | null = null;

/**
 * 初始化弹幕WebSocket服务
 */
export function initDanmakuService(authStore: any): DanmakuWebSocketService {
  if (!danmakuService) {
    danmakuService = new DanmakuWebSocketService(authStore);
  }
  return danmakuService;
}

/**
 * 获取弹幕服务实例
 */
export function getDanmakuService(): DanmakuWebSocketService | null {
  return danmakuService;
}

// Vue组合式API弹幕服务集成
export function useDanmakuWebSocket(videoId: string) {
  const authStore = useAuthStore();
  const service = initDanmakuService(authStore);
  const isConnected = ref(false);
  const roomInfo = ref<RoomInfo | null>(null);

  // 连接管理
  const connect = () => {
    if (authStore.user?.id && videoId) {
      service.connect(videoId, authStore.user.id.toString());
    }
  };

  // 断开连接
  const disconnect = () => {
    service.disconnect();
  };

  // 发送弹幕
  const sendDanmaku = (message: Omit<DanmakuMessage, 'id' | 'timestamp'>) => {
    return service.sendDanmaku(message);
  };

  // 获取房间信息
  const getRoomInfo = () => {
    service.getRoomInfo();
  };

  // 事件监听
  const onDanmaku = (callback: (message: DanmakuMessage) => void) => {
    service.on('danmaku-message', callback);
  };

  const onSystem = (callback: (message: DanmakuMessage) => void) => {
    service.on('system-message', callback);
  };

  const onRoomInfo = (callback: (info: RoomInfo) => void) => {
    service.on('room-info', callback);
  };

  const onConnected = (callback: () => void) => {
    service.on('connected', callback);
  };

  const onDisconnected = (callback: (reason: string) => void) => {
    service.on('disconnected', callback);
  };

  const onError = (callback: (error: any) => void) => {
    service.on('error', callback);
  };

  const onHeartbeat = (callback: (response: HeartbeatResponse) => void) => {
    service.on('heartbeat-response', callback);
  };

  // 设置事件监听器
  onMounted(() => {
    connect();
    service.on('connected', () => (isConnected.value = true));
    service.on('disconnected', () => (isConnected.value = false));
  });

  onUnmounted(() => {
    disconnect();
  });

  return {
    isConnected,
    roomInfo,
    connect,
    disconnect,
    sendDanmaku,
    getRoomInfo,
    onDanmaku,
    onSystem,
    onRoomInfo,
    onConnected,
    onDisconnected,
    onError,
    onHeartbeat,
  };
}

import { ref, computed } from 'vue';
import { useAuthStore } from '@/stores/auth';
import { mediaApi } from '@/api';
import type { MediaResource } from '@/types/media';
import type { Recommendation, RecommendationType } from '@/types/history';

export const useRecommendationService = () => {
  const authStore = useAuthStore();
  const isLoading = ref(false);
  const error = ref<string | null>(null);
  const recommendations = ref<Recommendation[]>([]);
  const personalizedMedia = ref<MediaResource[]>([]);

  // 基于用户观看历史生成推荐
  const generatePersonalizedRecommendations = async (limit: number = 10) => {
    if (!authStore.isAuthenticated) {
      return [];
    }

    try {
      isLoading.value = true;
      error.value = null;

      // 获取用户观看历史
      const watchHistory = await mediaApi.getWatchHistory({ limit: 20 });

      // 获取用户收藏
      const favorites = await mediaApi.getFavorites({ limit: 20 });

      // 提取用户偏好的类型和标签
      const userPreferences = analyzeUserPreferences([
        ...watchHistory.data.map(item => item.mediaResource),
        ...favorites.data,
      ]);

      // 基于偏好获取推荐
      const recommendedMedia = await mediaApi.getRecommendedMedia({
        limit,
      });

      personalizedMedia.value = recommendedMedia;
      return recommendedMedia;
    } catch (err) {
      console.error('生成个性化推荐失败:', err);
      error.value = '获取推荐失败';
      return [];
    } finally {
      isLoading.value = false;
    }
  };

  // 分析用户偏好
  const analyzeUserPreferences = (mediaList: any[]) => {
    const typeCount: Record<string, number> = {};
    const genreCount: Record<string, number> = {};
    const ratingSum: Record<string, number> = {};
    const ratingCount: Record<string, number> = {};

    mediaList.forEach(media => {
      // 统计类型偏好
      if (media.type) {
        typeCount[media.type] = (typeCount[media.type] || 0) + 1;
      }

      // 统计类型偏好
      if (media.genres) {
        media.genres.forEach((genre: string) => {
          genreCount[genre] = (genreCount[genre] || 0) + 1;
        });
      }

      // 统计评分偏好
      if (media.rating) {
        const type = media.type;
        ratingSum[type] = (ratingSum[type] || 0) + media.rating;
        ratingCount[type] = (ratingCount[type] || 0) + 1;
      }
    });

    // 找出最偏好的类型
    const preferredTypes = Object.entries(typeCount)
      .sort(([, a], [, b]) => b - a)
      .slice(0, 3)
      .map(([type]) => type);

    // 找出最偏好的类型
    const preferredGenres = Object.entries(genreCount)
      .sort(([, a], [, b]) => b - a)
      .slice(0, 5)
      .map(([genre]) => genre);

    // 计算平均评分偏好
    const avgRatingByType: Record<string, number> = {};
    Object.keys(ratingSum).forEach(type => {
      avgRatingByType[type] = ratingSum[type] / ratingCount[type];
    });

    return {
      preferredTypes,
      preferredGenres,
      avgRatingByType,
      totalWatched: mediaList.length,
    };
  };

  // 获取相似推荐
  const getSimilarMedia = async (mediaId: string, limit: number = 8) => {
    try {
      const media = await mediaApi.getMediaById(mediaId);

      // 基于当前媒体的特征获取相似内容
      const similarMedia = await mediaApi.getMediaByType(media.type, {
        limit,
        minRating: Math.max(0, (media.rating || 0) - 1),
        sortBy: 'rating',
        sortOrder: 'DESC',
      });

      return similarMedia.data.filter(m => m.id !== parseInt(mediaId));
    } catch (err) {
      console.error('获取相似媒体失败:', err);
      return [];
    }
  };

  // 获取趋势内容
  const getTrendingMedia = async (limit: number = 10) => {
    try {
      const trending = await mediaApi.getPopularMedia(limit, {
        sortBy: 'viewCount',
        sortOrder: 'DESC',
      });
      return trending;
    } catch (err) {
      console.error('获取趋势内容失败:', err);
      return [];
    }
  };

  // 计算推荐分数
  const calculateRecommendationScore = (
    media: MediaResource,
    userPreferences: ReturnType<typeof analyzeUserPreferences>,
  ) => {
    let score = 0;

    // 类型匹配分数 (40%)
    if (userPreferences.preferredTypes.includes(media.type)) {
      score += 40;
    }

    // 类型匹配分数 (30%)
    if (media.genres) {
      const matchingGenres = media.genres.filter(genre =>
        userPreferences.preferredGenres.includes(genre),
      );
      score += (matchingGenres.length / Math.max(1, userPreferences.preferredGenres.length)) * 30;
    }

    // 评分匹配分数 (20%)
    if (media.rating && userPreferences.avgRatingByType[media.type]) {
      const ratingDiff = Math.abs(media.rating - userPreferences.avgRatingByType[media.type]);
      score += Math.max(0, 20 - ratingDiff * 5);
    }

    // 观看次数分数 (10%)
    if (media.viewCount) {
      score += Math.min(10, Math.log10(media.viewCount + 1));
    }

    return score;
  };

  // 生成推荐理由
  const generateRecommendationReason = (
    media: MediaResource,
    userPreferences: ReturnType<typeof analyzeUserPreferences>,
    type: RecommendationType,
  ) => {
    const reasons = [];

    switch (type) {
      case 'personalized':
        if (userPreferences.preferredTypes.includes(media.type)) {
          reasons.push(`根据您喜欢的${media.type}类型推荐`);
        }
        if (media.genres && media.genres.some(g => userPreferences.preferredGenres.includes(g))) {
          reasons.push(
            `包含您偏好的${media.genres.find(g => userPreferences.preferredGenres.includes(g))}类型`,
          );
        }
        if (media.rating && media.rating >= 8) {
          reasons.push('高评分内容');
        }
        break;

      case 'similar':
        reasons.push('与您观看的内容相似');
        break;

      case 'trending':
        reasons.push('热门推荐');
        break;

      case 'popular':
        reasons.push('受欢迎内容');
        break;
    }

    return reasons.join('，') || '为您推荐';
  };

  // 深度学习推荐算法（简化版）
  const mlRecommendation = async (limit: number = 10) => {
    if (!authStore.isAuthenticated) {
      return [];
    }

    try {
      // 获取用户历史数据
      const userHistory = await mediaApi.getWatchHistory({ limit: 50 });
      const userFavorites = await mediaApi.getFavorites({ limit: 30 });

      // 构建用户画像
      const userProfile = {
        watchedTypes: {} as Record<string, number>,
        watchedGenres: {} as Record<string, number>,
        avgWatchTime: 0,
        completionRate: 0,
        ratingTrend: 'stable' as 'increasing' | 'stable' | 'decreasing',
      };

      // 分析用户画像
      userHistory.data.forEach((item: any) => {
        if (item.mediaResource?.type) {
          userProfile.watchedTypes[item.mediaResource.type] =
            (userProfile.watchedTypes[item.mediaResource.type] || 0) + 1;
        }
        if (item.mediaResource?.genres) {
          item.mediaResource.genres.forEach((genre: string) => {
            userProfile.watchedGenres[genre] = (userProfile.watchedGenres[genre] || 0) + 1;
          });
        }

        // 计算观看完成度
        if (item.duration && item.currentTime) {
          userProfile.completionRate += item.currentTime / item.duration;
        }
      });

      userProfile.completionRate /= Math.max(1, userHistory.data.length);
      userProfile.avgWatchTime =
        userHistory.data.reduce((sum: number, item: any) => sum + (item.currentTime || 0), 0) /
        Math.max(1, userHistory.data.length);

      // 获取候选媒体
      const candidateMedia = await mediaApi.getMediaList({ limit: 100 });

      // 计算推荐分数
      const scoredMedia = candidateMedia.data.map(media => {
        const score = calculateMLScore(media, userProfile);
        return { ...media, score };
      });

      // 返回最高分的媒体
      return scoredMedia
        .sort((a, b) => b.score - a.score)
        .slice(0, limit)
        .map(({ score, ...media }) => media);
    } catch (err) {
      console.error('ML推荐失败:', err);
      return [];
    }
  };

  // ML分数计算
  const calculateMLScore = (media: MediaResource, userProfile: any) => {
    let score = 0;

    // 类型权重 (30%)
    const typeScore = userProfile.watchedTypes[media.type] || 0;
    score +=
      (typeScore /
        Math.max(
          1,
          (Object.values(userProfile.watchedTypes) as number[]).reduce((a, b) => a + b, 0),
        )) *
      30;

    // 类型权重 (25%)
    if (media.genres) {
      const genreScore = media.genres.reduce(
        (sum, genre) => sum + (userProfile.watchedGenres[genre] || 0),
        0,
      );
      const totalGenreViews = (Object.values(userProfile.watchedGenres) as number[]).reduce(
        (a, b) => a + b,
        0,
      );
      score += (genreScore / Math.max(1, totalGenreViews)) * 25;
    }

    // 评分权重 (20%)
    if (media.rating) {
      score += Math.min(20, media.rating * 2);
    }

    // 观看完成度匹配 (15%)
    if (userProfile.completionRate > 0.7 && media.duration) {
      // 为观看完成度高的用户推荐较长内容
      score += media.duration > 120 ? 15 : 5;
    } else if (userProfile.completionRate < 0.3 && media.duration) {
      // 为观看完成度低的用户推荐较短内容
      score += media.duration < 60 ? 15 : 5;
    }

    // 新鲜度权重 (10%)
    const daysSinceCreated =
      (Date.now() - new Date(media.createdAt).getTime()) / (1000 * 60 * 60 * 24);
    if (daysSinceCreated < 30) {
      score += 10;
    } else if (daysSinceCreated < 90) {
      score += 5;
    }

    return score;
  };

  return {
    // 状态
    isLoading: computed(() => isLoading.value),
    error: computed(() => error.value),
    recommendations: computed(() => recommendations.value),
    personalizedMedia: computed(() => personalizedMedia.value),

    // 方法
    generatePersonalizedRecommendations,
    getSimilarMedia,
    getTrendingMedia,
    mlRecommendation,
    analyzeUserPreferences,
    calculateRecommendationScore,
    generateRecommendationReason,

    // 计算属性
    isAuthenticated: computed(() => authStore.isAuthenticated),
    hasRecommendations: computed(() => recommendations.value.length > 0),
  };
};

/**
 * 资源缓存管理器
 */

// 缓存配置
export interface CacheConfig {
  name: string;
  maxSize: number; // 最大缓存条目数
  ttl: number; // 生存时间（毫秒）
  storageType: 'memory' | 'local' | 'session'; // 存储类型
  compression?: boolean; // 是否压缩数据
  cleanupInterval?: number; // 清理间隔（毫秒）
}

// 缓存条目
export interface CacheEntry<T> {
  key: string;
  value: T;
  timestamp: number;
  ttl: number;
  accessCount: number;
  lastAccess: number;
  size: number;
}

// 缓存统计
export interface CacheStats {
  hits: number;
  misses: number;
  evictions: number;
  size: number;
  maxSize: number;
  hitRate: number;
  entries: number;
  memoryUsage: number;
}

export class ResourceCache<T = any> {
  private config: CacheConfig;
  private cache: Map<string, CacheEntry<T>>;
  private stats: CacheStats;
  private cleanupTimer?: ReturnType<typeof setInterval>;
  private changeListeners: Map<string, (key: string, value: T | null) => void> = new Map();

  constructor(config: CacheConfig) {
    this.config = {
      cleanupInterval: 60000, // 默认1分钟清理一次
      compression: false,
      ...config,
    };

    this.cache = new Map();
    this.stats = {
      hits: 0,
      misses: 0,
      evictions: 0,
      size: 0,
      maxSize: this.config.maxSize,
      hitRate: 0,
      entries: 0,
      memoryUsage: 0,
    };

    this.loadFromStorage();
    this.startCleanup();
  }

  // 设置缓存
  set(key: string, value: T, ttl?: number): void {
    const size = this.calculateSize(value);

    // 如果缓存已满，清理空间
    if (this.cache.size >= this.config.maxSize) {
      this.evict();
    }

    const entry: CacheEntry<T> = {
      key,
      value,
      timestamp: Date.now(),
      ttl: ttl || this.config.ttl,
      accessCount: 0,
      lastAccess: Date.now(),
      size,
    };

    this.cache.set(key, entry);
    this.updateStats('set', size);
    this.saveToStorage();
    this.notifyChange(key, value);
  }

  // 获取缓存
  get(key: string): T | null {
    const entry = this.cache.get(key);

    if (!entry) {
      this.updateStats('miss');
      return null;
    }

    // 检查是否过期
    if (this.isExpired(entry)) {
      this.delete(key);
      this.updateStats('miss');
      return null;
    }

    // 更新访问信息
    entry.accessCount++;
    entry.lastAccess = Date.now();

    this.updateStats('hit');
    this.notifyChange(key, entry.value);

    return entry.value;
  }

  // 检查缓存是否存在
  has(key: string): boolean {
    const entry = this.cache.get(key);
    if (!entry) return false;

    if (this.isExpired(entry)) {
      this.delete(key);
      return false;
    }

    return true;
  }

  // 删除缓存
  delete(key: string): boolean {
    const deleted = this.cache.delete(key);
    if (deleted) {
      this.updateStats('delete');
      this.saveToStorage();
      this.notifyChange(key, null);
    }
    return deleted;
  }

  // 清空缓存
  clear(): void {
    this.cache.forEach((entry, key) => {
      this.notifyChange(key, null);
    });
    this.cache.clear();
    this.stats.entries = 0;
    this.stats.size = 0;
    this.stats.memoryUsage = 0;
    this.saveToStorage();
  }

  // 获取所有键
  keys(): string[] {
    return Array.from(this.cache.keys());
  }

  // 获取所有值
  values(): T[] {
    return Array.from(this.cache.values()).map(entry => entry.value);
  }

  // 获取所有条目
  entries(): Array<{ key: string; value: T }> {
    return Array.from(this.cache.entries()).map(([key, entry]) => ({
      key,
      value: entry.value,
    }));
  }

  // 获取缓存大小
  size(): number {
    return this.cache.size;
  }

  // 获取缓存统计信息
  getStats(): CacheStats {
    return { ...this.stats };
  }

  // 批量获取
  batchGet(keys: string[]): (T | null)[] {
    return keys.map(key => this.get(key));
  }

  // 批量设置
  batchSet(entries: Array<{ key: string; value: T; ttl?: number }>): void {
    entries.forEach(({ key, value, ttl }) => {
      this.set(key, value, ttl);
    });
  }

  // 模糊匹配获取
  getFuzzy(pattern: string, limit = 5): Array<{ key: string; value: T }> {
    const results: Array<{ key: string; value: T; score: number }> = [];

    this.cache.forEach((entry, key) => {
      const score = this.calculateFuzzyScore(key, pattern);
      if (score > 0.5) {
        // 0.5 是模糊匹配的阈值
        results.push({ key, value: entry.value, score });
      }
    });

    return results
      .sort((a, b) => b.score - a.score)
      .slice(0, limit)
      .map(({ key, value }) => ({ key, value }));
  }

  // 添加变化监听器
  onChange(key: string, callback: (key: string, value: T | null) => void): void {
    this.changeListeners.set(key, callback);
  }

  // 移除变化监听器
  offChange(key: string): void {
    this.changeListeners.delete(key);
  }

  // 清理过期缓存
  cleanup(): number {
    let count = 0;
    const now = Date.now();

    this.cache.forEach((entry, key) => {
      if (this.isExpired(entry)) {
        this.delete(key);
        count++;
      }
    });

    return count;
  }

  // 清理最久未使用的缓存
  cleanupLRU(count = Math.ceil(this.config.maxSize * 0.2)): number {
    const entries = Array.from(this.cache.entries())
      .map(([key, entry]) => ({ key, entry }))
      .sort((a, b) => a.entry.lastAccess - b.entry.lastAccess);

    let deletedCount = 0;
    for (let i = 0; i < Math.min(count, entries.length); i++) {
      const { key } = entries[i];
      if (this.delete(key)) {
        deletedCount++;
      }
    }

    return deletedCount;
  }

  // 清理最少使用的缓存
  cleanupLFU(count = Math.ceil(this.config.maxSize * 0.2)): number {
    const entries = Array.from(this.cache.entries())
      .map(([key, entry]) => ({ key, entry }))
      .sort((a, b) => a.entry.accessCount - b.entry.accessCount);

    let deletedCount = 0;
    for (let i = 0; i < Math.min(count, entries.length); i++) {
      const { key } = entries[i];
      if (this.delete(key)) {
        deletedCount++;
      }
    }

    return deletedCount;
  }

  // 序列化缓存到存储
  private saveToStorage(): void {
    if (this.config.storageType === 'memory') return;

    try {
      const data = {
        cache: Array.from(this.cache.entries()),
        stats: this.stats,
        timestamp: Date.now(),
      };

      const serialized = JSON.stringify(data);

      // 压缩数据
      if (this.config.compression) {
        // 这里可以添加压缩逻辑
        // serialized = compress(serialized)
      }

      if (this.config.storageType === 'local') {
        localStorage.setItem(`cache_${this.config.name}`, serialized);
      } else if (this.config.storageType === 'session') {
        sessionStorage.setItem(`cache_${this.config.name}`, serialized);
      }
    } catch (error) {
      console.warn(`Failed to save cache ${this.config.name} to storage:`, error);
    }
  }

  // 从存储加载缓存
  private loadFromStorage(): void {
    if (this.config.storageType === 'memory') return;

    try {
      let serialized: string | null = null;

      if (this.config.storageType === 'local') {
        serialized = localStorage.getItem(`cache_${this.config.name}`);
      } else if (this.config.storageType === 'session') {
        serialized = sessionStorage.getItem(`cache_${this.config.name}`);
      }

      if (!serialized) return;

      // 解压缩数据
      if (this.config.compression) {
        // 这里可以添加解压缩逻辑
        // serialized = decompress(serialized)
      }

      const data = JSON.parse(serialized);

      // 重构缓存
      this.cache = new Map(data.cache || []);

      // 更新统计
      if (data.stats) {
        this.stats = { ...data.stats, maxSize: this.config.maxSize };
      }

      // 清理过期条目
      this.cleanup();
    } catch (error) {
      console.warn(`Failed to load cache ${this.config.name} from storage:`, error);
    }
  }

  // 开始自动清理
  private startCleanup(): void {
    if (this.config.cleanupInterval && this.config.cleanupInterval > 0) {
      this.cleanupTimer = setInterval(() => {
        this.cleanup();
      }, this.config.cleanupInterval);
    }
  }

  // 停止自动清理
  private stopCleanup(): void {
    if (this.cleanupTimer) {
      clearInterval(this.cleanupTimer);
      this.cleanupTimer = undefined;
    }
  }

  // 淘汰缓存
  private evict(): void {
    // 优先清理过期的
    if (this.cleanup() > 0) {
      return;
    }

    // 使用LRU策略
    this.cleanupLRU(1);

    this.stats.evictions++;
  }

  // 检查缓存是否过期
  private isExpired(entry: CacheEntry<T>): boolean {
    return Date.now() - entry.timestamp > entry.ttl;
  }

  // 计算数据大小
  private calculateSize(value: T): number {
    try {
      return JSON.stringify(value).length * 2; // 简单估算，2字节每字符
    } catch {
      return 1024; // 默认1KB
    }
  }

  // 计算模糊匹配分数
  private calculateFuzzyScore(key: string, pattern: string): number {
    if (!key || !pattern) return 0;

    // 简单的包含匹配
    if (key.includes(pattern)) return 1.0;

    // 模糊匹配逻辑
    const patternLower = pattern.toLowerCase();
    const keyLower = key.toLowerCase();

    if (patternLower === keyLower) return 1.0;

    // 部分匹配
    let score = 0;
    let patternIndex = 0;
    let keyIndex = 0;

    while (patternIndex < patternLower.length && keyIndex < keyLower.length) {
      if (patternLower[patternIndex] === keyLower[keyIndex]) {
        score++;
        patternIndex++;
      } else {
        score *= 0.9;
        keyIndex++;
      }
    }

    return score / Math.max(patternLower.length, keyLower.length);
  }

  // 更新统计信息
  private updateStats(action: 'hit' | 'miss' | 'set' | 'delete', size = 0): void {
    switch (action) {
      case 'hit':
        this.stats.hits++;
        break;
      case 'miss':
        this.stats.misses++;
        break;
      case 'set':
        this.stats.entries = this.cache.size;
        this.stats.size += size;
        break;
      case 'delete':
        this.stats.entries = this.cache.size;
        this.stats.size = Math.max(0, this.stats.size - size);
        break;
    }

    // 计算命中率
    const total = this.stats.hits + this.stats.misses;
    this.stats.hitRate = total > 0 ? this.stats.hits / total : 0;

    // 估算内存使用
    this.stats.memoryUsage = this.stats.size;
  }

  // 通知变化
  private notifyChange(key: string, value: T | null): void {
    const callback = this.changeListeners.get(key);
    if (callback) {
      try {
        callback(key, value);
      } catch (error) {
        console.error(`Cache change listener error for key ${key}:`, error);
      }
    }
  }

  // 销毁缓存
  destroy(): void {
    this.stopCleanup();
    this.clear();
    this.changeListeners.clear();
  }
}

// 创建预配置的缓存实例
export const createCache = <T = any>(config: CacheConfig) => new ResourceCache<T>(config);

// 默认配置
export const DEFAULT_CACHE_CONFIG = {
  maxSize: 100,
  ttl: 300000, // 5分钟
  storageType: 'memory',
  compression: false,
  cleanupInterval: 60000,
} satisfies Omit<CacheConfig, 'name'>;

// 创建默认缓存
export const createDefaultCache = <T = any>(name: string, overrides?: Partial<CacheConfig>) => {
  return createCache<T>({
    name,
    ...DEFAULT_CACHE_CONFIG,
    ...overrides,
  } as CacheConfig);
};

// 全局缓存实例
export const globalCache = createDefaultCache('global', {
  maxSize: 500,
  ttl: 1800000, // 30分钟
});

// API缓存实例
export const apiCache = createDefaultCache('api', {
  maxSize: 1000,
  ttl: 300000, // 5分钟
  storageType: 'session',
});

// 图片缓存实例
export const imageCache = createDefaultCache('images', {
  maxSize: 200,
  ttl: 3600000, // 1小时
  storageType: 'local',
  compression: true,
});

// 组件缓存实例
export const componentCache = createDefaultCache('components', {
  maxSize: 50,
  ttl: 600000, // 10分钟
  storageType: 'memory',
});

// 导出缓存工具函数
export const cacheUtils = {
  // 创建缓存键
  createKey: (namespace: string, ...parts: string[]): string => {
    return `${namespace}:${parts.join(':')}`;
  },

  // 创建带有版本控制的缓存键
  createVersionedKey: (namespace: string, version: string, ...parts: string[]): string => {
    return `${namespace}:${version}:${parts.join(':')}`;
  },

  // 创建带有时间戳的缓存键
  createTimestampKey: (namespace: string, timestamp: number, ...parts: string[]): string => {
    return `${namespace}:${timestamp}:${parts.join(':')}`;
  },

  // 计算缓存大小
  calculateCacheSize: (cache: ResourceCache): number => {
    const stats = cache.getStats();
    return stats.size;
  },

  // 清理所有缓存
  clearAllCaches: () => {
    globalCache.clear();
    apiCache.clear();
    imageCache.clear();
    componentCache.clear();
  },

  // 获取所有缓存的统计信息
  getAllCacheStats: () => ({
    global: globalCache.getStats(),
    api: apiCache.getStats(),
    images: imageCache.getStats(),
    components: componentCache.getStats(),
  }),

  // 优化缓存配置
  optimizeConfig: (
    config: CacheConfig,
    memoryInfo?: { used: number; total: number },
  ): CacheConfig => {
    if (!memoryInfo) return config;

    const memoryUsagePercent = memoryInfo.used / memoryInfo.total;

    // 如果内存使用超过80%，减少缓存大小
    if (memoryUsagePercent > 0.8) {
      config.maxSize = Math.floor(config.maxSize * 0.7);
      config.cleanupInterval = Math.max(10000, config.cleanupInterval * 0.8);
    }
    // 如果内存使用小于50%，可以增加缓存大小
    else if (memoryUsagePercent < 0.5) {
      config.maxSize = Math.floor(config.maxSize * 1.2);
    }

    return config;
  },
};

import { defineStore } from 'pinia';
import { ref, computed } from 'vue';
import { mediaApi } from '@/api/media';
import type { PaginatedResponse, PaginationParams, FilterParams } from '@/types/api';
import type { MediaResource, MediaQueryParams } from '@/types/media';

// 定义分页类型
interface Pagination {
  page: number;
  limit: number;
  total: number;
  totalPages: number;
}

export const useMediaStore = defineStore('media', () => {
  const mediaList = ref<MediaResource[]>([]);
  const currentMedia = ref<MediaResource | null>(null);
  const loading = ref(false);
  const pagination = ref<Pagination>({
    page: 1,
    limit: 10,
    total: 0,
    totalPages: 0,
  });

  const hasMore = computed(() => {
    return pagination.value.page < pagination.value.totalPages;
  });

  const fetchMediaList = async (params: MediaQueryParams = {}) => {
    loading.value = true;
    try {
      const response = await mediaApi.getMediaList(params);
      mediaList.value = response.data;
      pagination.value = {
        page: params.page || 1,
        limit: params.limit || 10,
        total: response.total || 0,
        totalPages: Math.ceil((response.total || 0) / (params.limit || 10)),
      };
      return response;
    } catch (error) {
      console.error('获取媒体列表失败:', error);
      throw error;
    } finally {
      loading.value = false;
    }
  };

  const fetchMediaDetail = async (id: string | number) => {
    loading.value = true;
    try {
      const response = await mediaApi.getMediaById(String(id));
      currentMedia.value = response;
      return response;
    } catch (error) {
      console.error('获取媒体详情失败:', error);
      throw error;
    } finally {
      loading.value = false;
    }
  };

  const fetchPopularMedia = async (limit = 10, params?: MediaQueryParams) => {
    try {
      const response = await mediaApi.getPopularMedia(limit, params);
      return response;
    } catch (error) {
      console.error('获取热门媒体失败:', error);
      throw error;
    }
  };

  const fetchLatestMedia = async (limit = 10, params?: MediaQueryParams) => {
    try {
      const response = await mediaApi.getLatestMedia(limit, params);
      return response;
    } catch (error) {
      console.error('获取最新媒体失败:', error);
      throw error;
    }
  };

  const fetchTopRatedMedia = async (limit = 10, minRating = 8, params?: MediaQueryParams) => {
    try {
      const response = await mediaApi.getTopRatedMedia(limit, minRating, params);
      return response;
    } catch (error) {
      console.error('获取高评分媒体失败:', error);
      throw error;
    }
  };

  const fetchRecommendations = async (mediaId: string | number, limit = 6) => {
    try {
      return await mediaApi.getSimilarMedia(mediaId, limit);
    } catch (error) {
      console.error('获取推荐媒体失败:', error);
      throw error;
    }
  };

  const searchMedia = async (query: string, params?: MediaQueryParams) => {
    loading.value = true;
    try {
      const response = await mediaApi.searchMedia(query, params);
      mediaList.value = response.data;
      pagination.value = {
        page: response.page,
        limit: response.limit,
        total: response.total,
        totalPages: response.totalPages,
      };
      return response;
    } catch (error) {
      console.error('搜索媒体失败:', error);
      throw error;
    } finally {
      loading.value = false;
    }
  };

  const fetchMediaByType = async (type: string, params?: MediaQueryParams) => {
    loading.value = true;
    try {
      const response = await mediaApi.getMediaByType(type, params);
      mediaList.value = response.data;
      pagination.value = {
        page: response.page,
        limit: response.limit,
        total: response.total,
        totalPages: response.totalPages,
      };
      return response;
    } catch (error) {
      console.error('获取类型媒体失败:', error);
      throw error;
    } finally {
      loading.value = false;
    }
  };

  const incrementViewCount = async (id: string) => {
    try {
      await mediaApi.incrementViewCount(id);
    } catch (error) {
      console.error('增加观看次数失败:', error);
    }
  };

  const toggleFavorite = async (id: string, currentState?: boolean) => {
    try {
      const response = await mediaApi.toggleFavorite(id, currentState);
      // 清除相关缓存
      mediaApi.clearCache();
      return response.isFavorited;
    } catch (error) {
      console.error('切换收藏状态失败:', error);
      throw error;
    }
  };

  const fetchFavoriteStatus = async (id: string) => {
    try {
      const response = await mediaApi.getFavoriteStatus(id);
      return response.isFavorited;
    } catch (error) {
      console.error('获取收藏状态失败:', error);
      throw error;
    }
  };

  const fetchFavorites = async (params?: MediaQueryParams) => {
    loading.value = true;
    try {
      const response = await mediaApi.getFavorites(params);
      mediaList.value = response.data;
      pagination.value = {
        page: response.page,
        limit: response.limit,
        total: response.total,
        totalPages: response.totalPages,
      };
      return response;
    } catch (error) {
      console.error('获取收藏媒体失败:', error);
      throw error;
    } finally {
      loading.value = false;
    }
  };

  const clearCurrentMedia = () => {
    currentMedia.value = null;
  };

  const resetMediaList = () => {
    mediaList.value = [];
    pagination.value = {
      page: 1,
      limit: 10,
      total: 0,
      totalPages: 0,
    };
  };

  const loadMore = async (params?: MediaQueryParams) => {
    if (!hasMore.value || loading.value) return;

    loading.value = true;
    try {
      const nextPage = pagination.value.page + 1;
      const response = await mediaApi.getMediaList({
        ...params,
        page: nextPage,
        limit: pagination.value.limit,
      });

      mediaList.value = [...mediaList.value, ...response.data];
      pagination.value = {
        page: response.page,
        limit: response.limit,
        total: response.total,
        totalPages: response.totalPages,
      };
      return response;
    } catch (error) {
      console.error('加载更多媒体失败:', error);
      throw error;
    } finally {
      loading.value = false;
    }
  };

  return {
    mediaList,
    currentMedia,
    loading,
    pagination,
    hasMore,
    fetchMediaList,
    fetchMediaDetail,
    fetchPopularMedia,
    fetchLatestMedia,
    fetchTopRatedMedia,
    fetchRecommendations,
    searchMedia,
    fetchMediaByType,
    incrementViewCount,
    toggleFavorite,
    fetchFavoriteStatus,
    fetchFavorites,
    clearCurrentMedia,
    resetMediaList,
    loadMore,
  };
});

import { defineStore } from 'pinia';
import { ref, computed, watch } from 'vue';

export type Theme = 'light' | 'dark' | 'auto';

export const useThemeStore = defineStore('theme', () => {
  // 状态
  const theme = ref<Theme>('auto'); // 默认跟随系统
  const darkModeOverride = ref<boolean | null>(null); // 用户手动覆盖

  // 计算当前主题
  const currentTheme = computed<Theme>(() => {
    // 优先使用用户手动设置
    if (darkModeOverride.value !== null) {
      return darkModeOverride.value ? 'dark' : 'light';
    }

    // 如果设置为 auto，则检查系统偏好
    if (theme.value === 'auto') {
      // 检查系统是否支持暗黑模式
      if (window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches) {
        return 'dark';
      }
      return 'light';
    }

    return theme.value;
  });

  // 判断是否为暗黑模式
  const isDarkMode = computed<boolean>(() => {
    return currentTheme.value === 'dark';
  });

  // 应用主题到文档
  const applyTheme = (newTheme: Theme) => {
    const html = document.documentElement;

    // 移除可能存在的主题类
    html.classList.remove('light-theme', 'dark-theme');

    // 添加对应的主题类
    if (newTheme === 'dark') {
      html.classList.add('dark-theme');
    } else if (newTheme === 'light') {
      html.classList.add('light-theme');
    }

    // 设置主题属性供CSS使用
    html.setAttribute('data-theme', newTheme);
  };

  // 设置主题
  const setTheme = (newTheme: Theme) => {
    theme.value = newTheme;
    darkModeOverride.value = null; // 重置手动覆盖
    applyTheme(newTheme);

    // 保存到本地存储
    localStorage.setItem('theme', newTheme);
  };

  // 手动切换暗黑模式
  const toggleDarkMode = () => {
    darkModeOverride.value = !isDarkMode.value;
    const newTheme = darkModeOverride.value ? 'dark' : 'light';
    applyTheme(newTheme);

    // 保存到本地存储
    localStorage.setItem('darkModeOverride', darkModeOverride.value.toString());
  };

  // 初始化主题
  const initTheme = () => {
    // 从本地存储恢复设置
    const savedTheme = localStorage.getItem('theme') as Theme;
    const savedOverride = localStorage.getItem('darkModeOverride');

    if (savedTheme) {
      theme.value = savedTheme;
    }

    if (savedOverride) {
      darkModeOverride.value = savedOverride === 'true';
    }

    // 应用当前主题
    applyTheme(currentTheme.value);

    // 监听系统主题变化（仅在 auto 模式下）
    if (theme.value === 'auto') {
      const mediaQuery = window.matchMedia('(prefers-color-scheme: dark)');

      mediaQuery.addEventListener('change', e => {
        if (darkModeOverride.value === null) {
          const newTheme = e.matches ? 'dark' : 'light';
          applyTheme(newTheme);
        }
      });
    }
  };

  // 暴露方法和状态
  return {
    // 状态
    theme,
    currentTheme,
    isDarkMode,
    darkModeOverride,

    // 方法
    setTheme,
    toggleDarkMode,
    initTheme,

    // 计算属性
    isAuto: computed(() => theme.value === 'auto' && darkModeOverride.value === null),
    themeIcon: computed(() => {
      if (isDarkMode.value) return '🌙️';
      return '☀️';
    }),
  };
});

