import axios, { type AxiosInstance } from 'axios';
import type { AxiosRequestConfig, AxiosResponse } from 'axios';

interface CacheConfig {
  ttl?: number; // 默认5分钟
  key?: string; // 自定义缓存key
  forceRefresh?: boolean; // 强制刷新
  enabled?: boolean; // 是否启用缓存，默认true
}

// 扩展 AxiosRequestConfig 以包含缓存配置
interface CachedAxiosRequestConfig extends AxiosRequestConfig {
  cacheConfig?: CacheConfig;
}

interface CacheItem<T = any> {
  data: T;
  timestamp: number;
  ttl: number;
  key: string;
}

/**
 * API缓存工具类
 */
class APICacheManager {
  private cache = new Map<string, CacheItem>();
  private maxSize = 1000; // 最大缓存条目数
  private cleanupInterval: number | null = null;

  constructor() {
    // 定期清理过期缓存
    this.startCleanup();
  }

  /**
   * 生成缓存key
   */
  private generateKey(config: CachedAxiosRequestConfig): string {
    const { url, method, params, data } = config;
    const normalizedUrl = (url || '').replace(/\/$/, ''); // 移除尾部斜杠

    // 基于URL、方法、参数和数据生成唯一key
    const keyObj = {
      url: normalizedUrl,
      method: method?.toLowerCase() || 'get',
      params: params ? JSON.stringify(params) : '',
      data: data ? JSON.stringify(data) : '',
    };

    return btoa(JSON.stringify(keyObj));
  }

  /**
   * 检查缓存是否有效
   */
  private isCacheValid(item: CacheItem): boolean {
    const now = Date.now();
    return now - item.timestamp < item.ttl;
  }

  /**
   * 获取缓存数据
   */
  private getCache<T = any>(key: string): T | null {
    const item = this.cache.get(key);
    if (!item || !this.isCacheValid(item)) {
      return null;
    }
    return item.data;
  }

  /**
   * 设置缓存数据
   */
  private setCache<T = any>(key: string, data: T, ttl: number): void {
    // 清理过期的缓存
    this.cleanupExpired();

    // 如果缓存已满，删除最旧的条目
    if (this.cache.size >= this.maxSize) {
      const oldestKey = this.cache.keys().next().value;
      if (oldestKey) {
        this.cache.delete(oldestKey);
      }
    }

    this.cache.set(key, {
      data,
      timestamp: Date.now(),
      ttl,
      key,
    });
  }

  /**
   * 清理过期缓存
   */
  private cleanupExpired(): void {
    const now = Date.now();
    const keysToDelete: string[] = [];

    this.cache.forEach((item, key) => {
      if (now - item.timestamp >= item.ttl) {
        keysToDelete.push(key);
      }
    });

    keysToDelete.forEach(key => this.cache.delete(key));
  }

  /**
   * 启动定期清理
   */
  private startCleanup(): void {
    this.cleanupInterval = setInterval(() => {
      this.cleanupExpired();
    }, 60000); // 每分钟清理一次
  }

  /**
   * 中断请求处理
   */
  private async handleRequest<T = any>(
    config: AxiosRequestConfig,
    cacheKey: string,
    cacheConfig: CacheConfig,
  ): Promise<AxiosResponse<T>> {
    try {
      const response = await axios(config);

      // 缓存成功的响应
      if (response.status >= 200 && response.status < 300) {
        const ttl = cacheConfig.ttl || 300000; // 默认5分钟
        this.setCache(cacheKey, response.data, ttl);
      }

      return response;
    } catch (error) {
      // 对于某些错误，可以返回缓存的旧数据
      if (error.response?.status === 503 || error.response?.status === 504) {
        const cachedData = this.getCache(cacheKey);
        if (cachedData) {
          // 返回缓存的旧数据，并标记为过期数据
          return {
            ...error.response,
            data: cachedData,
            status: 200,
            cached: true,
            cachedAt: this.cache.get(cacheKey)?.timestamp,
          };
        }
      }

      throw error;
    }
  }

  /**
   * 请求拦截器
   */
  public async requestInterceptor(
    config: CachedAxiosRequestConfig,
  ): Promise<CachedAxiosRequestConfig> {
    // 只缓存GET请求，除非显式配置
    if (config.method?.toLowerCase() !== 'get' && !config.cacheConfig?.enabled) {
      return config;
    }

    const cacheConfig = config.cacheConfig || {};
    if (cacheConfig.enabled === false) {
      return config;
    }

    if (cacheConfig.forceRefresh) {
      return config;
    }

    const key = cacheConfig.key || this.generateKey(config);
    const cachedData = this.getCache(key);

    if (cachedData) {
      // 如果有缓存数据，直接返回，不发送网络请求
      throw Object.assign(new Error('Cache hit'), {
        __cacheHit: true,
        config,
      });
    }

    return config;
  }

  /**
   * 响应拦截器
   */
  public async responseInterceptor(error: any): Promise<any> {
    if (!error?.__cacheHit) {
      throw error;
    }

    // 如果是缓存命中，构造响应对象
    const config = error.config as CachedAxiosRequestConfig;
    const cacheConfig = config.cacheConfig || {};
    const key = cacheConfig.key || this.generateKey(config);
    const cachedData = this.getCache(key);

    if (cachedData) {
      return {
        data: cachedData,
        status: 200,
        statusText: 'OK',
        headers: {},
        config,
        cached: true,
        cachedAt: this.cache.get(key)?.timestamp,
      };
    }

    throw error;
  }

  /**
   * 清理指定key的缓存
   */
  public clearCache(key?: string): void {
    if (key) {
      this.cache.delete(key);
    } else {
      this.cache.clear();
    }
  }

  /**
   * 清理指定URL模式的缓存
   */
  public clearCacheByPattern(pattern: string | RegExp): void {
    const keysToDelete: string[] = [];

    this.cache.forEach((item, key) => {
      if (typeof pattern === 'string') {
        if (key.includes(pattern)) {
          keysToDelete.push(key);
        }
      } else if (pattern instanceof RegExp) {
        if (pattern.test(key)) {
          keysToDelete.push(key);
        }
      }
    });

    keysToDelete.forEach(key => this.cache.delete(key));
  }

  /**
   * 获取缓存统计
   */
  public getStats(): Object {
    const now = Date.now();
    let validCount = 0;
    let expiredCount = 0;
    let totalSize = 0;

    this.cache.forEach((item, key) => {
      totalSize += JSON.stringify(item).length;
      if (this.isCacheValid(item)) {
        validCount++;
      } else {
        expiredCount++;
      }
    });

    return {
      total: this.cache.size,
      valid: validCount,
      expired: expiredCount,
      hitRate: validCount / (this.cache.size || 1),
      size: totalSize,
    };
  }

  /**
   * 预加载缓存
   */
  public async preload(urls: string[], ttl: number = 300000): Promise<void> {
    const preloadPromises = urls.map(url => {
      return axios
        .get(url, { cacheConfig: { ttl } } as any)
        .then(() => undefined)
        .catch(() => undefined);
    });

    await Promise.allSettled(preloadPromises);
  }

  /**
   * 销毁清理
   */
  public destroy(): void {
    if (this.cleanupInterval) {
      clearInterval(this.cleanupInterval);
      this.cleanupInterval = null;
    }
    this.cache.clear();
  }
}

// 创建全局缓存管理器实例
export const apiCacheManager = new APICacheManager();

/**
 * 为axios实例添加缓存拦截器
 */
export const setupCacheInterceptors = (instance: AxiosInstance): void => {
  // 请求拦截器
  instance.interceptors.request.use(
    async (config: any) => {
      try {
        return await apiCacheManager.requestInterceptor(config);
      } catch (error) {
        if ((error as any)?.__cacheHit) {
          return Promise.reject(error);
        }
        return config;
      }
    },
    error => Promise.reject(error),
  );

  // 响应拦截器
  instance.interceptors.response.use(
    response => response,
    async error => {
      try {
        return await apiCacheManager.responseInterceptor(error);
      } catch (responseError) {
        return Promise.reject(responseError);
      }
    },
  );
};

/**
 * 缓存配置工具函数
 */
export const withCache = (
  config: CachedAxiosRequestConfig,
  cacheConfig?: CacheConfig,
): CachedAxiosRequestConfig => {
  return {
    ...config,
    cacheConfig: {
      ttl: 300000, // 默认5分钟
      enabled: true,
      ...cacheConfig,
    },
  };
};

/**
 * 强制刷新缓存
 */
export const forceRefresh = (
  config: CachedAxiosRequestConfig,
  cacheConfig?: Omit<CacheConfig, 'forceRefresh'>,
): CachedAxiosRequestConfig => {
  return withCache(config, {
    ...cacheConfig,
    forceRefresh: true,
  });
};

export default apiCacheManager;

import { ElMessage, ElNotification } from 'element-plus';
// import type { AxiosError } from 'axios'; // 暂时注释，以后可能用到

// 定义错误类型
export interface ApiError {
  message: string;
  status: number;
  data?: any;
}

export interface BusinessError {
  code: string;
  message: string;
  data?: any;
}

// 全局错误处理器
export class GlobalErrorHandler {
  // 通用错误处理方法
  static handle(error: any, defaultMessage: string = '操作失败'): ApiError {
    return this.handleApiError(error, defaultMessage);
  }

  // 处理API错误
  static handleApiError(error: any, defaultMessage: string = '操作失败'): ApiError {
    console.error('API Error:', error);

    // 提取错误信息
    let message = defaultMessage;
    let statusCode = 500;

    if (error.response) {
      // 服务器响应错误
      statusCode = error.response.status;
      const data = error.response.data;

      if (data && data.message) {
        message = data.message;
      } else if (data && data.error) {
        message = data.error;
      } else {
        switch (statusCode) {
          case 400:
            message = '请求参数错误';
            break;
          case 401:
            message = '未授权访问，请重新登录';
            break;
          case 403:
            message = '权限不足';
            break;
          case 404:
            message = '请求的资源不存在';
            break;
          case 409:
            message = '资源冲突';
            break;
          case 422:
            message = '数据验证失败';
            break;
          case 500:
            message = '服务器内部错误';
            break;
          case 502:
            message = '网关错误';
            break;
          case 503:
            message = '服务暂时不可用';
            break;
          case 504:
            message = '网关超时';
            break;
          default:
            message = `HTTP ${statusCode} 错误`;
        }
      }
    } else if (error.request) {
      // 网络错误
      message = '网络连接失败，请检查网络设置';
    } else {
      // 其他错误
      message = error.message || defaultMessage;
    }

    // 显示错误提示
    ElMessage({
      message,
      type: 'error',
      duration: 5000,
      showClose: true,
    });

    // 特殊错误处理
    if (statusCode === 401) {
      // 未授权错误，可能需要重新登录
      this.handleUnauthorizedError();
    }

    return {
      message,
      status: statusCode,
      data: error.response?.data,
    };
  }

  // 处理未授权错误
  static handleUnauthorizedError() {
    // 清除本地存储的认证信息
    localStorage.removeItem('token');

    // 显示通知
    ElNotification({
      title: '会话过期',
      message: '您的登录会话已过期，请重新登录',
      type: 'warning',
      duration: 0, // 持续显示直到用户操作
    });

    // 3秒后跳转到登录页面
    setTimeout(() => {
      window.location.href = '/login';
    }, 3000);
  }

  // 处理表单验证错误
  static handleValidationError(errors: Record<string, string[]>) {
    console.error('Validation Errors:', errors);

    // 构建错误消息
    const errorMessages = Object.entries(errors)
      .map(([field, messages]) => `${field}: ${messages.join(', ')}`)
      .join('\n');

    // 显示错误提示
    ElMessage({
      message: `表单验证失败:\n${errorMessages}`,
      type: 'error',
      duration: 5000,
      showClose: true,
    });

    return errorMessages;
  }

  // 处理业务逻辑错误
  static handleBusinessError(error: BusinessError) {
    console.error('Business Error:', error);

    // 根据错误代码显示特定消息
    const errorMap: Record<string, string> = {
      MEDIA_NOT_FOUND: '影视资源不存在',
      PLAY_SOURCE_NOT_FOUND: '播放源不存在',
      USER_ALREADY_EXISTS: '用户已存在',
      INVALID_CREDENTIALS: '用户名或密码错误',
      TOKEN_EXPIRED: '令牌已过期',
      INSUFFICIENT_PERMISSIONS: '权限不足',
      RESOURCE_CONFLICT: '资源冲突',
      VALIDATION_FAILED: '数据验证失败',
      NETWORK_ERROR: '网络连接失败',
      SERVER_ERROR: '服务器错误',
      RATE_LIMIT_EXCEEDED: '请求过于频繁，请稍后再试',
      INVALID_INPUT: '输入数据无效',
      OPERATION_NOT_ALLOWED: '不允许此操作',
      RESOURCE_LOCKED: '资源已被锁定',
      QUOTA_EXCEEDED: '配额已满',
      SERVICE_UNAVAILABLE: '服务暂时不可用',
    };

    const message = errorMap[error.code] || error.message || '操作失败';

    // 显示错误提示
    ElMessage({
      message,
      type: 'warning',
      duration: 5000,
      showClose: true,
    });

    return message;
  }

  // 处理网络错误
  static handleNetworkError(error: any) {
    console.error('Network Error:', error);

    let message = '网络连接失败';

    if (error.code) {
      switch (error.code) {
        case 'ECONNABORTED':
          message = '请求超时';
          break;
        case 'ENOTFOUND':
          message = '域名解析失败';
          break;
        case 'ECONNREFUSED':
          message = '连接被拒绝';
          break;
        case 'ETIMEDOUT':
          message = '连接超时';
          break;
        case 'EHOSTUNREACH':
          message = '主机不可达';
          break;
        case 'ENETUNREACH':
          message = '网络不可达';
          break;
        default:
          message = `网络错误: ${error.code}`;
      }
    }

    // 显示错误提示
    ElMessage({
      message,
      type: 'error',
      duration: 5000,
      showClose: true,
    });

    return message;
  }

  // 处理播放错误
  static handlePlaybackError(error: any) {
    console.error('Playback Error:', error);

    let message = '视频播放失败';

    if (error.name) {
      switch (error.name) {
        case 'NotAllowedError':
          message = '播放被阻止，请点击播放按钮';
          break;
        case 'NotSupportedError':
          message = '不支持的视频格式';
          break;
        case 'AbortError':
          message = '播放被中止';
          break;
        case 'NetworkError':
          message = '网络连接问题导致播放失败';
          break;
        case 'DecodeError':
          message = '视频解码失败';
          break;
        case 'SourceUnavailableError':
          message = '视频源不可用';
          break;
        default:
          message = `播放错误: ${error.name}`;
      }
    }

    // 显示错误提示
    ElMessage({
      message,
      type: 'error',
      duration: 5000,
      showClose: true,
    });

    return message;
  }

  // 处理异步操作错误
  static async handleAsyncError<T>(
    promise: Promise<T>,
    options: {
      defaultMessage?: string;
      showError?: boolean;
      showNotification?: boolean;
    } = {},
  ): Promise<{ success: boolean; data?: T; error?: ApiError }> {
    const { defaultMessage = '操作失败', showError = true, showNotification = false } = options;

    try {
      const result = await promise;
      return { success: true, data: result };
    } catch (error) {
      const errorInfo = this.handleApiError(error, defaultMessage);

      if (showNotification) {
        ElNotification({
          title: '操作失败',
          message: errorInfo.message,
          type: 'error',
        });
      }

      return { success: false, error: errorInfo };
    }
  }
}

